import React, { useState, useEffect } from "react";

function App() {
  const [apiResponse, test] = useState("");
  const db_info = useState("");


  // function to get the db info
  const call_db = () => {
    fetch("http://localhost:9000/testAPI/user/")
      .then((res) => res.text())
      .then((res) => test(res));
  };

    // Function to call the API
  const callAPI = () => {
    fetch("http://localhost:9000/testAPI")
      .then((res) => res.json())
  };


  // Runs once when the component loads
  useEffect(() => {
    callAPI();
    call_db();
  }, []);


function App() {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [message, setMessage] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();

    const response = await fetch("http://localhost:9000/testAPI/login", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        name: username,
        password: password
      })
    });

    const data = await response.json();
    setMessage(data.message);
  };

  return (
    <div className="App">
      <h1>Express + React Test</h1>

      <form onSubmit={handleSubmit}>
        <label htmlFor="name">username :</label>
        <input
          type="text"
          id="name"
          name="name"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
        />

        <br />

        <label htmlFor="password">password :</label>
        <input
          type="text"
          id="password"
          name="password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />

        <br />
        <br />

        <input type="submit" value="Submit" />
      </form>

      <p>{message}</p>
    </div>
  );
}
}
export default App;
